function getKeyAssignment%% get key assignment%% 2012 by Antoine Barbotglobal keysnCfdLvl = 2; % low, mid, high%% design keys based on systemsystemName = computer;if systemName(1) == 'M' % Mac%     keys.respButtons = [9, 13; 7, 14; 22, 15]; % [F & J] windows: [89 98]; mac: [9,13]; Linux: [42,45]    keys.respButtons = [7, 14; 9, 13]; % [F & J] windows: [89 98]; mac: [9,13]; Linux: [42,45]    keys.stopKey = 20; % [Q] mac: 20    keys.space = 44; % [space]     elseif systemName(1) == 'G' % linux, at least true for the L1 computer    keys.respButtons = [41, 46; 42, 45]; % each row represents a confidence level: row 1: low, row 2: high ...    keys.stopKey = 25;     keys.space = 66; else    disp('system not identified.')endassert(size(keys.respButtons, 1)==nCfdLvl)%%% RestrictKeysForKbCheck([keys.respButtons(:); keys.stopKey; keys.space]);